import Foundation

enum Environment {
    case development
    case staging
    case production
}

enum APIError: Error {
    case invalidURL
    case noData
    case decodingError
    case apiError(String)
}

class NetworkManager {
    
    static let shared = NetworkManager()
    private let baseURL = "https://api.example.com"
    
    func fetchData(for userId: String, environment: Environment, completion: @escaping (Result<User, APIError>) -> Void) {
        var urlString = ""
        switch environment {
            case .development:
                urlString = "\(baseURL)/development/\(userId)"
            case .staging:
                urlString = "\(baseURL)/staging/\(userId)"
            case .production:
                urlString = "\(baseURL)/production/\(userId)"
        }
        
        guard let url = URL(string: urlString) else {
            completion(.failure(.invalidURL))
            return
        }
        
        URLSession.shared.dataTask(with: url) { (data, response, error) in
            if let error = error {
                completion(.failure(.apiError(error.localizedDescription)))
                return
            }
            
            guard let data = data else {
                completion(.failure(.noData))
                return
            }
            
            do {
                let user = try JSONDecoder().decode(User.self, from: data)
                completion(.success(user))
            } catch {
                completion(.failure(.decodingError))
            }
        }.resume()
    }
    
    func authenticate(credentials: [String: String], environment: Environment, completion: @escaping (Result<String, APIError>) -> Void) {
        var urlString = ""
        switch environment {
            case .development:
                urlString = "\(baseURL)/development/authenticate"
            case .staging:
                urlString = "\(baseURL)/staging/authenticate"
            case .production:
                urlString = "\(baseURL)/production/authenticate"
        }
        
        guard let url = URL(string: urlString) else {
            completion(.failure(.invalidURL))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.httpBody = try? JSONSerialization.data(withJSONObject: credentials)
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        URLSession.shared.dataTask(with: request) { (data, response, error) in
            if let error = error {
                completion(.failure(.apiError(error.localizedDescription)))
                return
            }
            
            guard let data = data else {
                completion(.failure(.noData))
                return
            }
            
            if let token = String(data: data, encoding: .utf8) {
                completion(.success(token))
            } else {
                completion(.failure(.decodingError))
            }
        }.resume()
    }
}

